/**
 * Notification model and related types.
 *
 * All notification types, channels, and payloads are defined here.
 * Other developers adding new notification channels or types should
 * extend these definitions.
 */

/**
 * Supported notification channels. Each channel has a corresponding
 * adapter that implements the NotificationAdapter interface.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/**
 * Notification types map to business events that trigger notifications.
 */
export type NotificationType =
  | 'order:confirmation'
  | 'order:status-update'
  | 'user:welcome'
  | 'user:profile-updated';

/**
 * Priority levels for notification delivery.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  metadata?: Record<string, string>;
}

/**
 * A sent notification record, stored by the NotificationService.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  status: 'pending' | 'sent' | 'failed';
  sentAt: Date;
  metadata?: Record<string, string>;
}

/**
 * NotificationAdapter interface — the contract all notification channel
 * adapters must implement.
 *
 * Architecture constraint: ALL notification delivery goes through adapters.
 * The NotificationService maps events to NotificationPayloads and delegates
 * delivery to the adapter registered for each channel. To add a new channel:
 *
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create a new adapter implementing this interface in src/adapters/
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

/**
 * Result returned by an adapter after attempting to send a notification.
 */
export interface SendResult {
  success: boolean;
  errorMessage?: string;
}

/**
 * All notification channel adapters must implement this interface.
 */
export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must not throw — return a SendResult with success: false on failure.
   */
  send(payload: NotificationPayload): Promise<SendResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Currently a stub that logs sends in-memory. Replace the send()
 * implementation with a real email provider (SES, SendGrid, etc.)
 * when ready — the interface stays the same.
 */

import type { NotificationAdapter, SendResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Record of an email that was "sent" (stored in-memory for testing).
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send an email notification.
   * Stub implementation: stores the email in-memory and logs it.
   */
  async send(payload: NotificationPayload): Promise<SendResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);
    return { success: true };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven via EventBus.
 * - All notifications are triggered by EventBus events (never direct calls).
 * - Delivery is delegated to NotificationAdapter implementations.
 * - To add a new channel: implement NotificationAdapter, register it here.
 * - To add a new notification trigger: subscribe to the event in registerHandlers().
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface.
 * - All notification triggers must go through EventBus.emit().
 * - Adapters must not throw — they return SendResult with success: false on failure.
 *
 * Depends on:
 * - EventBus for receiving events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a channel.
   * Only one adapter per channel is allowed — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to EventBus events that trigger notifications.
   * All notification triggers are centralized here.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order:confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      type: 'order:status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
    });
  }

  /**
   * Handle user created event — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.send({
      type: 'user:welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
      priority: 'normal',
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   */
  private async send(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: Notification['priority'];
    metadata?: Record<string, string>;
  }): Promise<Notification> {
    const notification: Notification = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      status: 'pending',
      sentAt: new Date(),
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);
    if (adapter) {
      const result = await adapter.send({
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        channel: params.channel,
        priority: params.priority,
        metadata: params.metadata,
      });
      notification.status = result.success ? 'sent' : 'failed';
      if (!result.success) {
        this.logger.error(`Failed to send notification ${notification.id}: ${result.errorMessage ?? 'unknown error'}`);
      }
    } else {
      this.logger.warn(`No adapter registered for channel: ${params.channel}. Notification ${notification.id} stored as pending.`);
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} [${notification.status}] to ${params.recipient}`);
    return notification;
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications. Useful for testing.
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

